# Comparing two randomization procedures

library(shiny)
library(ggplot2)
library(dplyr)
library(DT)
library(tidyr)
library(randomizeR)

# --- Generate sequence based on method name ---
gen_seq <- function(method, N, ratio, labels) {
  labs <- labels
  pA <- ratio[1] / sum(ratio)
  
  if (method == "Complete") {
    trt <- ifelse(rbinom(N, 1, pA) == 1, labs[1], labs[2])
    return(trt)
  }
  if (method == "Merged Block") {
    return(labs[BlockMergeGen(N, ratio, labs)])
  }
  if (method == "Random Allocation Rule") {
    return(as.character(getRandList(genSeq(rarPar(N, ratio=ratio, groups=labs)))))
  }
  if (method == "Truncated Binomial Design") {
    return(as.character(getRandList(genSeq(tbdPar(N, ratio=ratio, groups=labs)))))
  }
  if (method == "Permuted Block Randomization") {
    block_len <- sum(ratio) * ceiling(N / sum(ratio))
    seq <- getRandList(genSeq(pbrPar(block_len, ratio=ratio, groups=labs)))
    return(as.character(seq[1:N]))
  }
  if (method == "Permuted Block Randomization with Random Blocks") {
    valid_rb <- c(2,4,6,8,10,12,16,20,24,30)
    valid_rb <- valid_rb[valid_rb %% sum(ratio) == 0]
    seq <- getRandList(genSeq(rpbrPar(N, rb=valid_rb, ratio=ratio,
                                      groups=labs, filledBlock=TRUE)))
    return(as.character(seq))
  }
  if (method == "Efron's Biased Coin") {
    # Efron's biased coin: only prob parameter, ratio not used
    return(as.character(getRandList(genSeq(ebcPar(N, p=0.67, groups=labs)))))
  }
  
  if (method == "Wei Urn") {
    return(as.character(getRandList(genSeq(udPar(N, ratio=ratio, groups=labs)))))
  }
  if (method == "Big Stick Design") {
    return(as.character(getRandList(genSeq(bsdPar(N, ratio=ratio, groups=labs)))))
  }
  stop("Unknown method")
}

# --- Merged Block generator ---
BlockMergeGen <- function(n, ratio, labels){
  length.blocks <- sum(ratio)
  nr.basis.blocks <- ceiling(n / length.blocks)
  basis1 <- as.numeric(as.factor(
    getRandList(genSeq(pbrPar(rep(length.blocks, nr.basis.blocks),
                              ratio=ratio, groups=labels)))
  ))[1:n]
  basis2 <- as.numeric(as.factor(
    getRandList(genSeq(pbrPar(rep(length.blocks, nr.basis.blocks),
                              ratio=ratio, groups=labels)))
  ))[1:n]
  res <- rep(0, n)
  row1or2 <- sample(c(1, 2), size=n, replace=TRUE)
  taken.from.2 <- 0
  for(i in 1:n){
    if(row1or2[i] == 1){res[i] <- basis1[i - taken.from.2]}
    if(row1or2[i] == 2){
      taken.from.2 <- taken.from.2 + 1
      res[i] <- basis2[taken.from.2]
    }
  }
  return(res)
}

# --- Covariate balance metrics ---
cov_balance_metrics <- function(dat, labels) {
  covs <- c("gender","age","stage")
  out <- tibble()
  for (v in covs) {
    tab <- dat %>%
      group_by(treatment, !!sym(v)) %>%
      summarise(n = n(), .groups="drop") %>%
      group_by(treatment) %>%
      mutate(prop = n/sum(n)) %>%
      ungroup()
    levels_v <- unique(dat[[v]])
    lvl1 <- levels_v[1]
    pA <- tab %>% filter(treatment==labels[1], !!sym(v)==lvl1) %>% pull(prop)
    pB <- tab %>% filter(treatment==labels[2], !!sym(v)==lvl1) %>% pull(prop)
    pA <- ifelse(length(pA)==0,0,pA)
    pB <- ifelse(length(pB)==0,0,pB)
    p_pool <- (pA+pB)/2
    sd_pool <- sqrt(p_pool*(1-p_pool))
    std_diff <- ifelse(sd_pool>0,(pA-pB)/sd_pool,NA_real_)
    out <- bind_rows(out,
                     tibble(covariate=v, pA=pA, pB=pB, std_diff=std_diff))
  }
  out
}

format_balance_table <- function(bal, labels) {
  names(bal) <- c(
    "Covariate",
    paste("Proportion in", labels[1]),
    paste("Proportion in", labels[2]),
    "Standardized difference"
  )
  bal
}

# --- UI ---
ui <- fluidPage(
  titlePanel("Comparing Randomization Methods"),
  sidebarLayout(
    sidebarPanel(
      selectInput("method1","Method 1:",
                  choices=c("Complete","Merged Block","Random Allocation Rule","Truncated Binomial Design","Permuted Block Randomization","Permuted Block Randomization with Random Blocks","Efron's Biased Coin","Wei Urn","Big Stick Design"),
                  selected="Complete"),
      selectInput("method2","Method 2:",
                  choices=c("Complete","Merged Block","Random Allocation Rule","Truncated Binomial Design","Permuted Block Randomization","Permuted Block Randomization with Random Blocks","Efron's Biased Coin","Wei Urn","Big Stick Design"),
                  selected="Permuted Block Randomization"),
      numericInput("N","Number of participants (N):",20,min=2,step=1),
      textInput("labels","Treatment labels:",value="A,B"),
      textInput("ratio","Allocation ratio (comma-separated integers):",value="1,1"),
      hr(),
      sliderInput("pmale","Pr(Male):",min=0,max=1,value=0.5,step=0.05),
      sliderInput("pold","Pr(Old):",min=0,max=1,value=0.5,step=0.05),
      sliderInput("padv","Pr(Advanced stage):",min=0,max=1,value=0.5,step=0.05),
      hr(),
      numericInput("seed","Random seed (0=random):",0,min=0,step=1),
      actionButton("sim","Simulate one trial"),
      hr(),
      numericInput("nsim","Number of replicate trials (M):",value=100,min=10,step=10),
      actionButton("runsim","Run Monte Carlo")
    ),
    mainPanel(
      tabsetPanel(
        id="main_tabs",
        tabPanel("Single trial comparison", value="single_trial",
                 fluidRow(
                   column(6,tags$p("Method 1"),plotOutput("alloc_bar1")),
                   column(6,tags$p("Method 2"),plotOutput("alloc_bar2"))
                 ),
                 fluidRow(
                   column(6,plotOutput("cum_prop1")),
                   column(6,plotOutput("cum_prop2"))
                 ),
                 hr(),
                 fluidRow(
                   column(6,plotOutput("cov_by_arm1")),
                   column(6,plotOutput("cov_by_arm2"))
                 ),
                 hr(),
                 fluidRow(
                   column(6,tags$p("Covariate balance table"),DTOutput("cov_balance1")),
                   column(6,tags$p("Covariate balance table"),DTOutput("cov_balance2"))
                 ),
                 hr(),
                 fluidRow(
                   column(6,tags$p("Participant table"),DTOutput("subject_table1")),
                   column(6,tags$p("Participant table"),DTOutput("subject_table2"))
                 )
        ),
        tabPanel("Monte Carlo comparison", value="monte_carlo",
                 fluidRow(
                   column(6,plotOutput("hist_prop1")),
                   column(6,plotOutput("hist_prop2"))
                 ),
                 fluidRow(
                   column(6,plotOutput("hist_maxsd1")),
                   column(6,plotOutput("hist_maxsd2"))
                 ),
                 hr(),
                 fluidRow(
                   column(6,tags$p("Monte Carlo summary table"),DTOutput("mc_summary1")),
                   column(6,tags$p("Monte Carlo summary table"),DTOutput("mc_summary2"))
                 )
        ),
        tabPanel("How to use", value="how_to_use",
                 tags$p("Use this simulator to compare two randomization procedures for a two-arm trial. The aim is to see how different procedures behave in one trial and across many repeated trials, especially with respect to treatment allocation balance, covariate balance, and unpredictability."),
                 tags$p("Choose Method 1 and Method 2 in the sidebar. Complete randomization is the least predictable because each participant is assigned independently, but in finite samples it can still produce noticeable imbalance by chance. Restricted methods are designed to reduce some kinds of imbalance, often with a trade-off against unpredictability."),
                 tags$ul(
                   tags$li("Set the number of participants, treatment labels, and allocation ratio. The default A,B labels and 1,1 ratio represent equal allocation to two arms."),
                   tags$li("Set the probabilities for the simulated covariates: male, old, and advanced stage. These covariates are generated independently of treatment assignment so any imbalance is produced by chance and by the behavior of the randomization method."),
                   tags$li("Use the random seed to reproduce a single trial. A seed of 0 asks the app to choose a new seed.")
                 ),
                 tags$p("In Single trial comparison, click Simulate one trial to generate one trial under both methods. The bar charts compare the number of participants assigned to each treatment arm. The cumulative proportion plots show how the proportion assigned to the first treatment label evolves as participants enter the trial; the dotted red line is the target proportion from the allocation ratio."),
                 tags$p("The covariate plots show the distribution of gender, age, and stage within each treatment arm. The covariate balance tables summarize the proportion for the first listed level of each covariate in each arm and the standardized difference between arms. Larger absolute standardized differences indicate more imbalance. The participant tables show the simulated participant-level data behind the plots."),
                 tags$p("In Monte Carlo comparison, either click Run Monte Carlo or open the Monte Carlo comparison tab. The app repeats the trial M times for both selected methods. The proportion histograms show how often each method produces different realized proportions in the first treatment arm. The maximum standardized difference histograms summarize the largest absolute covariate imbalance observed across gender, age, and stage in each replicate trial."),
                 tags$p("The Monte Carlo summary tables report the average and standard deviation of the treatment-arm proportion and of the maximum standardized difference. These summaries help separate what happened in one random trial from the behavior expected over repeated trials."),
                 tags$p("Suggested exercises: compare Complete with Permuted Block Randomization for N = 20 and M = 100, then repeat with N = 200. Try changing the allocation ratio to 2,1 and watch how the target line and realized proportions change. Compare methods that strongly control treatment counts with methods that preserve more unpredictability, and ask which trade-off is most appropriate for a small trial."),
                 tags$p("Overall, this app helps you move from one simulated trial to the long-run behavior of randomization methods. Use the single-trial outputs to inspect a concrete allocation and its covariate balance, then use the Monte Carlo outputs to compare how often each method produces treatment imbalance or covariate imbalance across repeated trials. The main lesson is that randomization methods differ in how they balance treatment arms and covariates while preserving unpredictability.")
        ),
        tabPanel("Cite", value="cite",
                 tags$p("Please cite this software in publications or presentations that use it:"),
                 tags$p(
                   "Tamasi, Katalin. Comparing Randomization Methods, version 1.0. University Medical Center Groningen, 2026. Shiny application. ",
                   tags$a(
                     href = "https://katatam.github.io/randomization/compare_rand/",
                     "https://katatam.github.io/randomization/compare_rand/",
                     target = "_blank"
                   )
                 ),
                 hr(),
                 tags$p("Copyright 2026 Katalin Tamasi. This software is licensed under the MIT License. You may use, copy, modify, merge, publish, distribute, sublicense, and/or sell copies of the software, subject to the terms of the MIT License.")
        )
      )
    )
  )
)

# --- SERVER ---
server <- function(input, output, session){
  
  # Single trial sim
  sim_dat <- eventReactive(input$sim,{
    set.seed(if(input$seed>0) input$seed else sample.int(1e6,1))
    labs <- strsplit(input$labels,",")[[1]] %>% trimws()
    ratio <- as.numeric(strsplit(input$ratio,",")[[1]])
    
    dat1 <- tibble(id=1:input$N,
                   treatment=gen_seq(input$method1,input$N,ratio,labs),
                   gender=ifelse(rbinom(input$N,1,input$pmale)==1,"Male","Female"),
                   age=ifelse(rbinom(input$N,1,input$pold)==1,"Old","Young"),
                   stage=ifelse(rbinom(input$N,1,input$padv)==1,"Advanced","Early"))
    dat2 <- tibble(id=1:input$N,
                   treatment=gen_seq(input$method2,input$N,ratio,labs),
                   gender=ifelse(rbinom(input$N,1,input$pmale)==1,"Male","Female"),
                   age=ifelse(rbinom(input$N,1,input$pold)==1,"Old","Young"),
                   stage=ifelse(rbinom(input$N,1,input$padv)==1,"Advanced","Early"))
    list(dat1=dat1,dat2=dat2,ratio=ratio,labels=labs,
         method1=input$method1,method2=input$method2)
  },ignoreNULL=FALSE)
  
  # Plots for single trial
  output$alloc_bar1 <- renderPlot({
    agg <- sim_dat()$dat1 %>% count(treatment)
    ymax <- max(table(sim_dat()$dat1$treatment), table(sim_dat()$dat2$treatment))
    ggplot(agg,aes(x=treatment,y=n,fill=treatment))+geom_col(show.legend=FALSE)+
      ylim(0,ymax)+labs(title=sim_dat()$method1,x="Treatment",y="N")+theme_minimal()
  })
  output$alloc_bar2 <- renderPlot({
    agg <- sim_dat()$dat2 %>% count(treatment)
    ymax <- max(table(sim_dat()$dat1$treatment), table(sim_dat()$dat2$treatment))
    ggplot(agg,aes(x=treatment,y=n,fill=treatment))+geom_col(show.legend=FALSE)+
      ylim(0,ymax)+labs(title=sim_dat()$method2,x="Treatment",y="N")+theme_minimal()
  })
  
  output$cum_prop1 <- renderPlot({
    dat <- sim_dat()$dat1; ratio <- sim_dat()$ratio; labs <- sim_dat()$labels
    props <- dat %>% mutate(cumA=cumsum(treatment==labs[1]),cumProp=cumA/id)
    ggplot(props,aes(x=id,y=cumProp))+geom_step()+
      geom_hline(yintercept=ratio[1]/sum(ratio),linetype="dotted",color="red")+
      ylim(0,1)+labs(title=paste("Cumulative proportion",labs[1],"-",sim_dat()$method1))
  })
  output$cum_prop2 <- renderPlot({
    dat <- sim_dat()$dat2; ratio <- sim_dat()$ratio; labs <- sim_dat()$labels
    props <- dat %>% mutate(cumA=cumsum(treatment==labs[1]),cumProp=cumA/id)
    ggplot(props,aes(x=id,y=cumProp))+geom_step()+
      geom_hline(yintercept=ratio[1]/sum(ratio),linetype="dotted",color="red")+
      ylim(0,1)+labs(title=paste("Cumulative proportion",labs[1],"-",sim_dat()$method2))
  })
  
  output$cov_by_arm1 <- renderPlot({
    long <- sim_dat()$dat1 %>% pivot_longer(cols=c(gender,age,stage),names_to="cov",values_to="level")
    ggplot(long,aes(x=treatment,fill=level))+geom_bar(position="fill")+facet_wrap(~cov)+
      labs(title=paste("Covariates -",sim_dat()$method1))
  })
  output$cov_by_arm2 <- renderPlot({
    long <- sim_dat()$dat2 %>% pivot_longer(cols=c(gender,age,stage),names_to="cov",values_to="level")
    ggplot(long,aes(x=treatment,fill=level))+geom_bar(position="fill")+facet_wrap(~cov)+
      labs(title=paste("Covariates -",sim_dat()$method2))
  })
  
  output$cov_balance1 <- renderDT({
    bal <- cov_balance_metrics(sim_dat()$dat1, sim_dat()$labels) %>%
      format_balance_table(sim_dat()$labels)
    datatable(bal,options=list(dom='t')) %>%
      formatRound(columns=which(vapply(bal, is.numeric, logical(1))),digits=2)
  })
  output$cov_balance2 <- renderDT({
    bal <- cov_balance_metrics(sim_dat()$dat2, sim_dat()$labels) %>%
      format_balance_table(sim_dat()$labels)
    datatable(bal,options=list(dom='t')) %>%
      formatRound(columns=which(vapply(bal, is.numeric, logical(1))),digits=2)
  })
  
  # Subject tables
  output$subject_table1 <- renderDT({
    datatable(sim_dat()$dat1, options=list(pageLength=10))
  })
  output$subject_table2 <- renderDT({
    datatable(sim_dat()$dat2, options=list(pageLength=10))
  })
  
  # --- Monte Carlo simulation ---
  mc_trigger <- reactiveVal(0)
  observeEvent(input$runsim, {
    mc_trigger(mc_trigger() + 1)
  }, ignoreInit=TRUE)
  observeEvent(input$main_tabs, {
    if (identical(input$main_tabs, "monte_carlo")) {
      mc_trigger(mc_trigger() + 1)
    }
  }, ignoreInit=TRUE)
  
  mc_res <- eventReactive(mc_trigger(),{
    req(mc_trigger() > 0)
    labs <- strsplit(input$labels,",")[[1]] %>% trimws()
    ratio <- as.numeric(strsplit(input$ratio,",")[[1]])
    nsim <- input$nsim
    N <- input$N
    method1 <- input$method1
    method2 <- input$method2
    pmale <- input$pmale
    pold <- input$pold
    padv <- input$padv
    
    run_one <- function(method){
      props <- numeric(nsim)
      maxsd <- numeric(nsim)
      for(i in 1:nsim){
        trt <- gen_seq(method,N,ratio,labs)
        dat <- tibble(
          id=1:N,treatment=trt,
          gender=ifelse(rbinom(N,1,pmale)==1,"Male","Female"),
          age=ifelse(rbinom(N,1,pold)==1,"Old","Young"),
          stage=ifelse(rbinom(N,1,padv)==1,"Advanced","Early")
        )
        props[i] <- mean(dat$treatment==labs[1])
        bal <- cov_balance_metrics(dat, labs)
        abs_sd <- abs(bal$std_diff)
        abs_sd[is.na(abs_sd)] <- 0
        maxsd[i] <- max(abs_sd)
      }
      list(props=props,maxsd=maxsd)
    }
    
    list(m1=run_one(method1), m2=run_one(method2), ratio=ratio, labels=labs,
         method1=method1, method2=method2, nsim=nsim, N=N)
  })
  
  # MC Plots with same axes
  output$hist_prop1 <- renderPlot({
    res <- mc_res()
    all <- c(res$m1$props, res$m2$props)
    pA <- res$ratio[1] / sum(res$ratio)
    
    ggplot(data.frame(prop=res$m1$props), aes(x=prop)) +
      geom_histogram(bins=30, fill="steelblue", color="white") +
      xlim(min(all), max(all)) +
      geom_vline(xintercept = pA, linetype="dotted", color="red", size=1) +
      labs(title=paste("Proportion",res$labels[1],"-",res$method1),
           x="Treatment proportion",
           y="Number of replicate trials")
  })
  
  output$hist_prop2 <- renderPlot({
    res <- mc_res()
    all <- c(res$m1$props, res$m2$props)
    pA <- res$ratio[1] / sum(res$ratio)
    
    ggplot(data.frame(prop=res$m2$props), aes(x=prop)) +
      geom_histogram(bins=30, fill="steelblue", color="white") +
      xlim(min(all), max(all)) +
      geom_vline(xintercept = pA, linetype="dotted", color="red", size=1) +
      labs(title=paste("Proportion",res$labels[1],"-",res$method2),
           x="Treatment proportion",
           y="Number of replicate trials")
  })
  
  
  output$hist_maxsd1 <- renderPlot({
    res <- mc_res(); all <- c(res$m1$maxsd,res$m2$maxsd)
    ggplot(data.frame(maxsd=res$m1$maxsd),aes(x=maxsd))+
      geom_histogram(bins=30,fill="coral",color="white")+
      xlim(min(all),max(all))+labs(title=paste("Maximum standardized difference -",res$method1),
                                   x="Maximum standardized difference",
                                   y="Number of replicate trials")
  })
  output$hist_maxsd2 <- renderPlot({
    res <- mc_res(); all <- c(res$m1$maxsd,res$m2$maxsd)
    ggplot(data.frame(maxsd=res$m2$maxsd),aes(x=maxsd))+
      geom_histogram(bins=30,fill="coral",color="white")+
      xlim(min(all),max(all))+labs(title=paste("Maximum standardized difference -",res$method2),
                                   x="Maximum standardized difference",
                                   y="Number of replicate trials")
  })
  
  output$mc_summary1 <- renderDT({
    res <- mc_res()$m1
    df <- tibble(
      Measure=c("Mean treatment proportion","SD treatment proportion",
                "Mean maximum standardized difference","SD maximum standardized difference"),
      Value=c(mean(res$props),sd(res$props),mean(res$maxsd),sd(res$maxsd))
    )
    datatable(df,options=list(dom='t')) %>% formatRound(columns="Value",digits=2)
  })
  output$mc_summary2 <- renderDT({
    res <- mc_res()$m2
    df <- tibble(
      Measure=c("Mean treatment proportion","SD treatment proportion",
                "Mean maximum standardized difference","SD maximum standardized difference"),
      Value=c(mean(res$props),sd(res$props),mean(res$maxsd),sd(res$maxsd))
    )
    datatable(df,options=list(dom='t')) %>% formatRound(columns="Value",digits=2)
  })
}

shinyApp(ui, server)
